function makeUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const item = $json;

// Try every likely title location from merged Google Drive + Google Docs outputs
const title =
  item.title ||
  item.name ||
  item.document?.title ||
  item.document?.name ||
  item.drive?.name ||
  item.drive?.title ||
  item.file?.name ||
  item.file?.title ||
  $('Search WMMA Docs').item?.json?.name ||
  $('Search WMMA Docs').item?.json?.title ||
  $('Get a document').item?.json?.title ||
  $('Get a document').item?.json?.name ||
  '';

if (!title) {
  throw new Error(`Document title missing. Available keys: ${Object.keys(item).join(', ')}`);
}

let managerName = null;

// Pattern 1:
// Breanna Weekly Meeting WMMA - 2026/04/28 09:28 CDT - Notes by Gemini
let match = title.match(/^(.+?)\s+Weekly\s+(?:Manager\s+)?Meeting\s+WMMA/i);
if (match) {
  managerName = match[1].trim();
}

// Pattern 2:
// Apr 22, 2026 [WMMA] Amy Weekly Manager Meeting
if (!managerName) {
  match = title.match(/\[WMMA\]\s+(.+?)\s+Weekly\s+Manager\s+Meeting/i);
  if (match) {
    managerName = match[1].trim();
  }
}

// Pattern 3:
// fallback: any title containing "X Weekly Meeting"
if (!managerName) {
  match = title.match(/(?:^|\]\s*)(.+?)\s+Weekly\s+(?:Manager\s+)?Meeting/i);
  if (match) {
    managerName = match[1]
      .replace(/^\w{3,9}\s+\d{1,2},\s+\d{4}\s*/i, '')
      .trim();
  }
}

if (!managerName) {
  throw new Error(`Manager name not parsed from title: ${title}`);
}

// Normalize known names
const managerMap = {
  'Breanna Blanks': 'Breanna',
  'Brandon Stewart': 'Brandon',
  'Tammie Stewart': 'Tammie',
  'Tammy': 'Tammie',
  'Amy': 'Amy',
  'Breanna': 'Breanna',
  'Debbie': 'Debbie',
  'Dede': 'Dede',
  'Shelbie': 'Shelbie',
  'Chris': 'Chris',
  'Ashlie': 'Ashlie'
};

managerName = managerMap[managerName] || managerName;

// Parse meeting datetime
let meetingDatetime = null;

// Format: 2026/04/28 09:28 CDT
match = title.match(/(\d{4})\/(\d{2})\/(\d{2})\s+(\d{2}):(\d{2})/);
if (match) {
  const [, year, month, day, hour, minute] = match;
  meetingDatetime = `${year}-${month}-${day} ${hour}:${minute}:00`;
}

// Format: Apr 22, 2026
if (!meetingDatetime) {
  match = title.match(/([A-Za-z]{3,9})\s+(\d{1,2}),\s+(\d{4})/);
  if (match) {
    const parsed = new Date(`${match[1]} ${match[2]}, ${match[3]} 09:00:00`);
    if (!Number.isNaN(parsed.getTime())) {
      meetingDatetime = parsed.toISOString().slice(0, 19).replace('T', ' ');
    }
  }
}

if (!meetingDatetime) {
  throw new Error(`Meeting datetime not parsed from title: ${title}`);
}

// Monday week reference
const dt = new Date(meetingDatetime.replace(' ', 'T'));
const day = dt.getDay();

const monday = new Date(dt);
monday.setDate(dt.getDate() - ((day + 6) % 7));

const weekReference = monday.toISOString().slice(0, 10);

const driveFileId =
  item.documentId ||
  item.id ||
  item.fileId ||
  item.drive_file_id ||
  item.document?.documentId ||
  item.document?.id ||
  $('Search WMMA Docs').item?.json?.id ||
  $('Search WMMA Docs').item?.json?.documentId ||
  $('Get a document').item?.json?.documentId ||
  $('Get a document').item?.json?.id ||
  null;

const driveLastModified =
  item.modifiedTime ||
  item.drive_last_modified ||
  item.file?.modifiedTime ||
  item.drive?.modifiedTime ||
  $('Search WMMA Docs').item?.json?.modifiedTime ||
  null;

return [{
  json: {
    ...item,
    id: makeUuid(),
    drive_file_id: driveFileId,
    drive_last_modified: driveLastModified,
    manager_name: managerName,
    meeting_datetime: meetingDatetime,
    week_reference: weekReference,
    source_title: title
  }
}];

const doc = $json;

let fullText = '';

for (const el of doc.body?.content || []) {
  if (el.paragraph?.elements) {
    for (const pe of el.paragraph.elements) {
      if (pe.textRun?.content) {
        fullText += pe.textRun.content;
      }
    }
  }
}

// Normalize Google Docs weird spacing
fullText = fullText
  .replace(/\r/g, '')
  .replace(/\u000b/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function extractSection(text, startMarkers, endMarkers) {
  const starts = Array.isArray(startMarkers) ? startMarkers : [startMarkers];

  let startIndex = -1;

  for (const marker of starts) {
    const re = new RegExp(`(^|\\n)${escapeRegExp(marker)}\\s*\\n`, 'i');
    const match = text.match(re);

    if (match) {
      startIndex = match.index + match[0].length;
      break;
    }
  }

  if (startIndex === -1) return '';

  let endIndex = text.length;

  for (const marker of endMarkers) {
    const re = new RegExp(`(^|\\n)${escapeRegExp(marker)}\\s*\\n`, 'i');
    const slice = text.slice(startIndex);
    const match = slice.match(re);

    if (match) {
      const idx = startIndex + match.index;
      if (idx < endIndex) endIndex = idx;
    }
  }

  return text.substring(startIndex, endIndex).trim();
}

function cleanSectionText(text) {
  return String(text || '')
    .replace(/Rate this Summary:[\s\S]*?(?=\n\n|$)/gi, '')
    .replace(/Let us know what you think:[\s\S]*?(?=\n\n|$)/gi, '')
    .replace(/^We've updated the Decisions section.*$/gim, '')
    .replace(/^ALIGNED$/gim, '')
    .replace(/Did the screenshots[\s\S]*?(?=\n|$)/gi, '')
    .replace(/You should review Gemini's notes[\s\S]*$/gi, '')
    .replace(/How is the quality[\s\S]*$/gi, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function normalizeOwner(owner) {
  const v = String(owner || '').trim().toLowerCase();

  if (v === 'brandon stewart' || v === 'brandon') return 'Brandon';
  if (v === 'tammie stewart' || v === 'tammy stewart' || v === 'tammy' || v === 'tammie') return 'Tammie';
  if (v === 'breanna blanks' || v === 'breanna' || v === 'brianna blanks' || v === 'brianna') return 'Breanna';
  if (v === 'amy') return 'Amy';
  if (v === 'debbie') return 'Debbie';
  if (v === 'dede') return 'Dede';
  if (v === 'shelbie') return 'Shelbie';
  if (v === 'chris') return 'Chris';
  if (v === 'ashlie' || v === 'ashlie wagner') return 'Ashlie';

  return String(owner || '').trim();
}

const knownProperties = [
  'Adobe',
  'North Park',
  'NorthPark',
  'Courtyard',
  'Jefferson',
  'Riveredge',
  'Crosskeys',
  'Sagebrush',
  'Westminster',
  'Broadstone',
  'Nelson',
  'Oak Terrace',
  'Single Families and Small Multi'
];

function detectProperty(text) {
  const source = String(text || '');

  for (const property of knownProperties) {
    const re = new RegExp(`\\b${escapeRegExp(property)}\\b`, 'i');
    if (re.test(source)) {
      if (property === 'North Park') return 'NorthPark';
      return property;
    }
  }

  return null;
}

// Supports old test format and real Gemini format
const portfolioPerformance = cleanSectionText(extractSection(fullText, 'Portfolio Performance', [
  'Operational Issues',
  'Decisions',
  'Next steps',
  'Details'
]));

const operationalIssues = cleanSectionText(extractSection(fullText, 'Operational Issues', [
  'Decisions',
  'Next steps',
  'Details'
]));

const summary = cleanSectionText(extractSection(fullText, 'Summary', [
  'Decisions',
  'Next steps',
  'Details',
  'Rate this Summary'
]));

const details = cleanSectionText(extractSection(fullText, 'Details', [
  "You should review Gemini's notes",
  'How is the quality'
]));

const decisionsText = cleanSectionText(extractSection(fullText, 'Decisions', [
  'Next steps',
  'Details'
]));

const nextSteps = extractSection(fullText, 'Next steps', [
  'Details',
  "You should review Gemini's notes",
  'How is the quality'
]);

const changes = portfolioPerformance
  ? [portfolioPerformance]
  : summary
    ? [summary]
    : [];

const issues = operationalIssues
  ? [operationalIssues]
  : details
    ? [details]
    : [];

const decisions = decisionsText ? [decisionsText] : [];

// Extract actions
const actionLines = nextSteps
  .split('\n')
  .map(l => l.trim())
  .filter(l => l.startsWith('[') && l.includes(']') && l.includes(':'));

const actions = actionLines.map(line => {
  const match = line.match(/^\[(.*?)\]\s*(.*?):\s*(.*)$/);

  if (!match) return null;

  const rawOwner = match[1].trim();
  const title = match[2].trim();
  const detail = match[3].trim();

  const owner = normalizeOwner(rawOwner);
  const description = `${title}: ${detail}`;
  const dueMatch = detail.match(/(\d{4}-\d{2}-\d{2})/);
  const property_name = detectProperty(`${title} ${detail}`);

  return {
    description,
    owner,
    due_date: dueMatch ? dueMatch[1] : null,
    property_name
  };
}).filter(Boolean);

return [{
  json: {
    drive_file_id: doc.documentId,
    drive_last_modified: $json.modifiedTime || null,
    full_text: fullText,
    summary_structured: {
      changes,
      issues,
      decisions
    },
    actions
  }
}];

function makeUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const item = $json;
const fullText = item.full_text || '';

// Parse manager from title line
const managerMatch = fullText.match(/\[WMMA\]\s*(.*?)\s+Weekly Manager Meeting/i);
const manager_name = managerMatch ? managerMatch[1].trim() : null;

// Parse meeting date from first line if possible
const firstLine = fullText.split('\n')[0]?.trim();
let meetingDate = new Date(firstLine);

if (isNaN(meetingDate.getTime())) {
  meetingDate = new Date();
}

// Set meeting datetime
const meeting_datetime = meetingDate.toISOString().slice(0, 19).replace('T', ' ');

// Derive Monday week reference
const d = new Date(meetingDate);
const day = d.getDay();
const diff = d.getDate() - day + (day === 0 ? -6 : 1);
const monday = new Date(d.setDate(diff)).toISOString().slice(0, 10);

const created_at = new Date().toISOString().slice(0, 19).replace('T', ' ');

return [{
  json: {
    id: makeUuid(),
    drive_file_id: item.drive_file_id,
    drive_last_modified: item.drive_last_modified,
    manager_name,
    meeting_datetime,
    week_reference: monday,
    transcript_raw: null,
    full_text: item.full_text,
    summary_structured: item.summary_structured,
    actions: item.actions,
    created_at
  }
}];

const doc = $json;

let fullText = '';

for (const el of doc.body?.content || []) {
  if (el.paragraph?.elements) {
    for (const pe of el.paragraph.elements) {
      if (pe.textRun?.content) {
        fullText += pe.textRun.content;
      }
    }
  }
}

// Normalize
fullText = fullText.replace(/\r/g, '').trim();

// Split sections
function extractSection(text, start, endMarkers) {
  const startIndex = text.indexOf(start);
  if (startIndex === -1) return '';

  let endIndex = text.length;

  for (const marker of endMarkers) {
    const idx = text.indexOf(marker, startIndex + start.length);
    if (idx !== -1 && idx < endIndex) {
      endIndex = idx;
    }
  }

  return text.substring(startIndex + start.length, endIndex).trim();
}

// Normalize owner names to contract-safe values
function normalizeOwner(owner) {
  const v = String(owner || '').trim().toLowerCase();

  if (v === 'brandon stewart' || v === 'brandon') return 'Brandon';
  if (v === 'breanna blanks' || v === 'breanna' || v === 'brianna blanks' || v === 'brianna') return 'Breanna';

  return String(owner || '').trim();
}

// Detect property from action text
const knownProperties = [
  'Adobe',
  'NorthPark',
  'Courtyard',
  'Jefferson',
  'Riveredge',
  'Crosskeys',
  'Sagebrush',
  'Westminster',
  'Broadstone',
  'Nelson',
  'Oak Terrace',
  'Single Families and Small Multi'
];

function detectProperty(text) {
  for (const property of knownProperties) {
    const re = new RegExp(`\\b${property.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'i');
    if (re.test(text)) return property;
  }
  return null;
}

const portfolioPerformance = extractSection(fullText, 'Portfolio Performance', [
  'Operational Issues',
  'Decisions',
  'Next steps'
]);

const issues = extractSection(fullText, 'Operational Issues', [
  'Decisions',
  'Next steps'
]);

const decisions = extractSection(fullText, 'Decisions', [
  'Next steps'
]);

const nextSteps = extractSection(fullText, 'Next steps', []);

// Extract actions
const actionLines = nextSteps
  .split('\n')
  .map(l => l.trim())
  .filter(l => l.startsWith('[') && l.includes(']') && l.includes(':'));

const actions = actionLines.map(line => {
  const match = line.match(/^\[(.*?)\]\s*(.*?):\s*(.*)$/);

  if (!match) return null;

  const rawOwner = match[1].trim();
  const title = match[2].trim();
  const detail = match[3].trim();

  const owner = normalizeOwner(rawOwner);
  const description = `${title}: ${detail}`;

  const dueMatch = detail.match(/(\d{4}-\d{2}-\d{2})/);
  const property_name = detectProperty(`${title} ${detail}`);

  return {
    description,
    owner,
    due_date: dueMatch ? dueMatch[1] : null,
    property_name
  };
}).filter(Boolean);

return [{
  json: {
    drive_file_id: doc.documentId,
    drive_last_modified: $json.modifiedTime,
    full_text: fullText,
    summary_structured: {
      changes: portfolioPerformance ? [portfolioPerformance] : [],
      issues: issues ? [issues] : [],
      decisions: decisions ? [decisions] : []
    },
    actions
  }
}];

if (!$json.full_text || !String($json.full_text).trim()) {
  throw new Error('Missing full_text');
}

if (!$json.manager_name || !String($json.manager_name).trim()) {
  throw new Error('Manager name not parsed');
}

if (!$json.meeting_datetime) {
  throw new Error('Missing meeting_datetime');
}

if (!$json.week_reference) {
  throw new Error('Missing week_reference');
}

if (
  !$json.summary_structured ||
  !Array.isArray($json.summary_structured.changes) ||
  !Array.isArray($json.summary_structured.issues) ||
  !Array.isArray($json.summary_structured.decisions)
) {
  throw new Error('Invalid summary_structured shape');
}

if (!Array.isArray($json.actions)) {
  throw new Error('Invalid actions array');
}

if ($json.actions.length < 1 || $json.actions.length > 5) {
  throw new Error(`Expected 1-5 actions, got ${$json.actions.length}`);
}

return [{ json: $json }];
